package test;

public class allprimitivedatatypes {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		 // this is for Integer 
        byte byteV = 127;
        short shortV = 32000;
        int intV = 100000;
        long longV = 123456789L;

        // this is for Decimal 
        float floatV = 12.34f;
        double doubleV = 123.456789;

        // this  is for Char
        char charV = 'A';

        // this is for Bool 
        boolean boolv = true;

        System.out.println("Byte Value: " + byteV);
        System.out.println("Short Value: " + shortV);
        System.out.println("Int Value: " + intV);
        System.out.println("Long Value: " + longV);

        System.out.println("Float Value: " + floatV);
        System.out.println("Double Value: " + doubleV);

        System.out.println("Char Value: " + charV);

        System.out.println("Boolean Value: " + boolv);
	}

}
